/**
 * Competition Leaderboard Server Functions for TanStack Start
 *
 * Thin wrapper around the server leaderboard implementation.
 * Uses the configurable scoring system for all algorithms.
 *
 * @see @/server/competition-leaderboard for implementation
 */

import { createServerFn } from "@tanstack/react-start"
import { and, eq } from "drizzle-orm"
import { z } from "zod"
import { getDb } from "@/db"
import {
  competitionRegistrationsTable,
  competitionsTable,
} from "@/db/schemas/competitions"
import {
  programmingTracksTable,
  trackWorkoutsTable,
} from "@/db/schemas/programming"
import { TEAM_PERMISSIONS } from "@/db/schemas/teams"
import {
  addRequestContextAttribute,
  logInfo,
  logWarning,
} from "@/lib/logging"
import {
  getCompetitionLeaderboard,
  getEventLeaderboard,
  type EventLeaderboardEntry as ServerEventLeaderboardEntry,
  type CompetitionLeaderboardEntry as ServerLeaderboardEntry,
  type TeamMemberInfo as ServerTeamMemberInfo,
} from "@/server/competition-leaderboard"
import type { ScoringAlgorithm } from "@/types/scoring"
import { requireTeamPermission } from "@/utils/team-auth"

// ============================================================================
// Types (Re-export from server layer with additions)
// ============================================================================

export type TeamMemberInfo = ServerTeamMemberInfo

export type CompetitionLeaderboardEntry = ServerLeaderboardEntry

export type EventLeaderboardEntry = ServerEventLeaderboardEntry

/**
 * Response from the leaderboard function - includes scoring algorithm
 * for the frontend to display points appropriately
 */
export interface CompetitionLeaderboardResponse {
  entries: CompetitionLeaderboardEntry[]
  scoringAlgorithm: ScoringAlgorithm
}

// ============================================================================
// Input Schemas
// ============================================================================

const getCompetitionLeaderboardInputSchema = z.object({
  competitionId: z.string().min(1, "Competition ID is required"),
  divisionId: z.string().optional(),
  /**
   * When true, requests the organizer preview: includes all scored
   * events/divisions even if division results are unpublished.
   * Requires MANAGE_COMPETITIONS permission on the organizing team.
   */
  preview: z.boolean().optional(),
})

const getEventLeaderboardInputSchema = z.object({
  competitionId: z.string().min(1, "Competition ID is required"),
  trackWorkoutId: z.string().min(1, "Track workout ID is required"),
  divisionId: z.string().optional(),
})

// ============================================================================
// Server Functions
// ============================================================================

/**
 * Get the competition leaderboard with scoring algorithm info
 */
export const getCompetitionLeaderboardFn = createServerFn({ method: "GET" })
  .inputValidator((data: unknown) =>
    getCompetitionLeaderboardInputSchema.parse(data),
  )
  .handler(async ({ data }): Promise<CompetitionLeaderboardResponse> => {
    addRequestContextAttribute("competitionId", data.competitionId)
    if (data.divisionId) {
      addRequestContextAttribute("divisionId", data.divisionId)
    }
    addRequestContextAttribute("leaderboardPreview", data.preview === true)

    logInfo({
      message: "[Leaderboard] Fetch requested",
      attributes: {
        competitionId: data.competitionId,
        divisionId: data.divisionId ?? null,
        preview: data.preview === true,
      },
    })

    // Preview mode bypasses the publish filter so organizers can see
    // unpublished scores as they come in. It MUST be authorized against
    // the organizing team before we skip the filter.
    if (data.preview) {
      const db = getDb()
      const competition = await db.query.competitionsTable.findFirst({
        where: eq(competitionsTable.id, data.competitionId),
        columns: { id: true, organizingTeamId: true },
      })

      if (!competition) {
        logWarning({
          message: "[Leaderboard] Preview denied - competition not found",
          attributes: { competitionId: data.competitionId },
        })
        throw new Error("Competition not found")
      }

      await requireTeamPermission(
        competition.organizingTeamId,
        TEAM_PERMISSIONS.MANAGE_COMPETITIONS,
      )
    }

    const result = await getCompetitionLeaderboard({
      competitionId: data.competitionId,
      divisionId: data.divisionId,
      bypassPublicationFilter: data.preview === true,
    })

    const scoredEntries = result.entries.filter((e) =>
      e.eventResults.some((er) => er.rawScore !== null),
    ).length

    // Surface the first few entries as the client will render them so we can
    // see whether unscored athletes are sorting above scored ones.
    const topEntries = result.entries.slice(0, 10).map((e) => ({
      athleteName: e.athleteName,
      divisionId: e.divisionId,
      overallRank: e.overallRank,
      totalPoints: e.totalPoints,
      hasAnyScore: e.eventResults.some((er) => er.rawScore !== null),
    }))

    logInfo({
      message: "[Leaderboard] Fetch complete",
      attributes: {
        competitionId: data.competitionId,
        divisionId: data.divisionId ?? null,
        preview: data.preview === true,
        entryCount: result.entries.length,
        scoredEntryCount: scoredEntries,
        eventCount: result.events.length,
        scoringAlgorithm: result.scoringConfig.algorithm,
        topEntries,
      },
    })

    return {
      entries: result.entries,
      scoringAlgorithm: result.scoringConfig.algorithm,
    }
  })

/**
 * Get leaderboard for a specific event
 */
export const getEventLeaderboardFn = createServerFn({ method: "GET" })
  .inputValidator((data: unknown) => getEventLeaderboardInputSchema.parse(data))
  .handler(async ({ data }) => {
    return getEventLeaderboard({
      competitionId: data.competitionId,
      trackWorkoutId: data.trackWorkoutId,
      divisionId: data.divisionId,
    })
  })

// ============================================================================
// Legacy API (for backwards compatibility with existing components)
// ============================================================================

export interface LegacyLeaderboardEntry {
  userId: string
  userName: string
  userAvatar: string | null
  score: string | null
  aggregatedScore: number | null
  formattedScore: string
  scalingLevelId: string | null
  scalingLevelLabel: string | null
  scalingLevelPosition: number | null
  asRx: boolean
  completedAt: Date
  isTimeCapped?: boolean
}

const getLeaderboardDataInputSchema = z.object({
  competitionId: z.string().min(1, "Competition ID is required"),
  divisionId: z.string().optional(),
})

/**
 * Legacy leaderboard function for backwards compatibility.
 * Returns a simplified structure matching the old placeholder API.
 */
export const getLeaderboardDataFn = createServerFn({ method: "GET" })
  .inputValidator((data: unknown) => getLeaderboardDataInputSchema.parse(data))
  .handler(async ({ data }) => {
    const db = getDb()

    // Verify competition exists
    const competition = await db.query.competitionsTable.findFirst({
      where: eq(competitionsTable.id, data.competitionId),
    })

    if (!competition) {
      return { leaderboard: [], workouts: [] }
    }

    // Get published workouts for this competition
    const track = await db.query.programmingTracksTable.findFirst({
      where: eq(programmingTracksTable.competitionId, data.competitionId),
    })

    const trackWorkoutsWithWorkouts = track
      ? await db.query.trackWorkoutsTable.findMany({
          where: and(
            eq(trackWorkoutsTable.trackId, track.id),
            eq(trackWorkoutsTable.eventStatus, "published"),
          ),
          with: {
            workout: true,
          },
          orderBy: (trackWorkouts, { asc }) => [asc(trackWorkouts.trackOrder)],
        })
      : []

    // Get registrations for this competition
    const registrations = await db.query.competitionRegistrationsTable.findMany(
      {
        where: data.divisionId
          ? and(
              eq(competitionRegistrationsTable.eventId, data.competitionId),
              eq(competitionRegistrationsTable.divisionId, data.divisionId),
            )
          : eq(competitionRegistrationsTable.eventId, data.competitionId),
        with: {
          user: true,
          division: true,
        },
        orderBy: (regs, { asc }) => [asc(regs.registeredAt)],
      },
    )

    // Transform to legacy leaderboard format
    const leaderboard: LegacyLeaderboardEntry[] = registrations.map((reg) => {
      const fullName =
        `${reg.user.firstName || ""} ${reg.user.lastName || ""}`.trim()

      return {
        userId: reg.userId,
        userName: fullName || reg.user.email || "Unknown",
        userAvatar: reg.user.avatar,
        score: null,
        aggregatedScore: null,
        formattedScore: "N/A",
        scalingLevelId: reg.divisionId,
        scalingLevelLabel: reg.division?.label ?? null,
        scalingLevelPosition: reg.division?.position ?? null,
        asRx: false,
        completedAt: reg.registeredAt,
        isTimeCapped: false,
      }
    })

    return {
      leaderboard,
      workouts: trackWorkoutsWithWorkouts.map((tw) => ({
        id: tw.id,
        workoutId: tw.workoutId,
        name:
          (tw as unknown as { workout?: { name: string } }).workout?.name ??
          "Unknown Workout",
        trackOrder: tw.trackOrder,
      })),
    }
  })

            )?.url ?? null)
          : null,
        videoSubmissionId: isEventDivisionPublished(
          trackWorkout.id,
          divisionId,
        )
          ? (videoMap.get(
              `${registration.registration.id}:${trackWorkout.id}`,
            )?.submissionId ?? null)
          : null,
        parentEventId: trackWorkout.parentEventId,
        parentEventName: trackWorkout.parentEventId
          ? (parentNameMap.get(trackWorkout.parentEventId) ?? null)
          : null,
        isParentEvent: false,
        cappedRoundCount: roundSummary.cappedRoundCount,
        totalRoundCount: roundSummary.totalRoundCount,
        reviewSummary: buildReviewSummary(
          registration.registration.id,
          trackWorkout.id,
        ),
      })

      entry.totalPoints += points
    }

    // Athletes registered in this division who didn't submit a score for
    // this event tie at the worst position (activeCount + 1). Without this,
    // an absent submission would have totalPoints = 0 and outrank a
    // recorded submission under lower-is-better algorithms (online).
    const activeCount = eventScoreInputs.filter(
      (s) => s.status === "scored" || s.status === "cap",
    ).length
    const missingPlace = activeCount + 1
    const missingPoints = Math.round(
      calculatePointsForPlace({
        place: missingPlace,
        config: scoringConfig,
      }) * multiplier,
    )

    const scoredUserIds = new Set(divisionScores.map((s) => s.userId))
    const missingRegs = filteredRegistrations.filter(
      (r) =>
        (r.registration.divisionId || "open") === divisionId &&
        !scoredUserIds.has(r.user.id),
    )

    for (const reg of missingRegs) {
      const entry = leaderboardMap.get(reg.registration.id)
      if (!entry) continue

      const eventDivPublished = isEventDivisionPublished(
        trackWorkout.id,
        divisionId,
      )
      const videoInfo = videoMap.get(
        `${reg.registration.id}:${trackWorkout.id}`,
      )

      entry.eventResults.push({
        trackWorkoutId: trackWorkout.id,
        trackOrder: trackWorkout.trackOrder,
        eventName: trackWorkout.workout.name,
        scheme: trackWorkout.workout.scheme,
        rank: missingPlace,
        points: missingPoints,
        rawScore: null,
        formattedScore: "N/A",
        formattedTiebreak: null,
        penaltyType: null,
        penaltyPercentage: null,
        isDirectlyModified: false,
        videoUrl: eventDivPublished ? (videoInfo?.url ?? null) : null,
        videoSubmissionId: eventDivPublished
          ? (videoInfo?.submissionId ?? null)
          : null,
        parentEventId: trackWorkout.parentEventId,
        parentEventName: trackWorkout.parentEventId
          ? (parentNameMap.get(trackWorkout.parentEventId) ?? null)
          : null,
        isParentEvent: false,
        cappedRoundCount: 0,
        totalRoundCount: 0,
        reviewSummary: buildReviewSummary(
          reg.registration.id,
          trackWorkout.id,
        ),
      })

      entry.totalPoints += missingPoints
    }

    processed++
  }

  eventProcessingLog.push({
    trackWorkoutId: trackWorkout.id,
    eventName: trackWorkout.workout.name,
    eventStatus: trackWorkout.eventStatus ?? null,
    scoresInDivisionMap: scoresSeenForEvent - scoresMissingRegistration,
    divisionsWithScores: eventScoresByDivision.size,
    divisionsGatedOut: gatedOut,
    divisionsProcessed: processed,
  })

  // Add empty results for athletes who didn't complete this event
  for (const [regId, entry] of leaderboardMap) {
    const hasResult = entry.eventResults.some(
      (er) => er.trackWorkoutId === trackWorkout.id,
    )
    if (!hasResult) {
      entry.eventResults.push({
        trackWorkoutId: trackWorkout.id,
        trackOrder: trackWorkout.trackOrder,
        eventName: trackWorkout.workout.name,
        scheme: trackWorkout.workout.scheme,
        rank: 0,
        points: 0,
        rawScore: null,
        formattedScore: "N/A",
        formattedTiebreak: null,
        penaltyType: null,
        penaltyPercentage: null,
        isDirectlyModified: false,
        videoUrl: isEventDivisionPublished(trackWorkout.id, entry.divisionId)
          ? (videoMap.get(`${regId}:${trackWorkout.id}`)?.url ?? null)
          : null,
        videoSubmissionId: isEventDivisionPublished(
          trackWorkout.id,
          entry.divisionId,
        )
          ? (videoMap.get(`${regId}:${trackWorkout.id}`)?.submissionId ??
            null)
          : null,
        parentEventId: trackWorkout.parentEventId,
        parentEventName: trackWorkout.parentEventId
          ? (parentNameMap.get(trackWorkout.parentEventId) ?? null)
          : null,
        isParentEvent: false,
        cappedRoundCount: 0,
        totalRoundCount: 0,
        reviewSummary: isEventDivisionPublished(
          trackWorkout.id,
          entry.divisionId,
        )
          ? buildReviewSummary(regId, trackWorkout.id)
          : null,
      })
    }
  }
}

// Parent events are not scored directly — sub-events appear as top-level columns
// on the leaderboard, so we skip adding parent aggregate entries to eventResults.

const totalScoresProcessed = eventProcessingLog.reduce(
  (sum, e) => sum + e.scoresInDivisionMap,
  0,
)
const totalDivisionsGated = eventProcessingLog.reduce(
  (sum, e) => sum + e.divisionsGatedOut,
  0,
)

logInfo({
  message: "[Leaderboard] Event processing breakdown",
  attributes: {
    competitionId: params.competitionId,
    divisionId: params.divisionId ?? null,
    totalScoresProcessed,
    totalDivisionsGatedByPublishFilter: totalDivisionsGated,
    perEvent: eventProcessingLog,
  },
})

// Convert to array and apply tiebreakers for overall ranking
const leaderboard = Array.from(leaderboardMap.values())

// Group by division for ranking
const divisionGroups = new Map<string, CompetitionLeaderboardEntry[]>()
for (const entry of leaderboard) {
  const existing = divisionGroups.get(entry.divisionId) || []
  existing.push(entry)
  divisionGroups.set(entry.divisionId, existing)
}

// Apply tiebreakers within each division
for (const [_divisionId, entries] of divisionGroups) {
  // Build event placements map for tiebreaker
  const tiebreakerInput: TiebreakerInput = {
    athletes: entries.map((e) => ({
      userId: e.userId,
      totalPoints: e.totalPoints,
      eventPlacements: new Map(
        e.eventResults
          .filter((er) => er.rank > 0)
          .map((er) => [er.trackWorkoutId, er.rank]),
      ),
    })),
    config: scoringConfig.tiebreaker,
    scoringAlgorithm: scoringConfig.algorithm,
  }

  const rankedAthletes = applyTiebreakers(tiebreakerInput)

  // Update entries with final ranks
  for (const ranked of rankedAthletes) {
    const entry = entries.find((e) => e.userId === ranked.userId)
    if (entry) {
      entry.overallRank = ranked.rank
    }
  }
}

// Sort by overall rank
const sortedEntries = leaderboard.sort((a, b) => {
  // First by division, then by rank
  if (a.divisionId !== b.divisionId) {
    return a.divisionId.localeCompare(b.divisionId)
  }
  return a.overallRank - b.overallRank
})

// Build events list for the response — exclude parent events since sub-events
// appear as top-level columns on the leaderboard
const events = filteredTrackWorkouts
  .filter((tw) => !childEventIds.has(tw.id))
  .map((tw) => ({
    trackWorkoutId: tw.id,
    name: tw.workout.name,
    parentEventId: tw.parentEventId,
    parentEventName: tw.parentEventId
      ? (parentNameMap.get(tw.parentEventId) ?? null)
      : null,
    isParentEvent: false,
  }))

return {
  entries: sortedEntries,

/**
 * Scoring Algorithm Factory
 *
 * Central factory that dispatches to the correct scoring algorithm based on
 * configuration. Provides a unified interface for calculating event points
 * regardless of which algorithm is being used.
 *
 * Algorithms:
 * - traditional: Fixed step point deduction from first place
 * - p_score: Performance-based scoring that rewards margin of victory
 * - custom: Template-based with optional place-specific overrides
 *
 * @see docs/plans/configurable-scoring-system.md
 */

import type { WorkoutScheme } from "@/lib/scoring/types"
import type {
  PScoreConfig,
  ScoringConfig,
  TraditionalConfig,
} from "@/types/scoring"
import { calculateCustomPoints } from "./custom"
import { calculateOnlinePoints } from "./online"
import { calculatePScore, type PScoreInput } from "./p-score"
import { calculateTraditionalPoints } from "./traditional"

export {
  calculateCustomPoints,
  generatePointsTable,
  WINNER_TAKES_MORE_TABLE,
} from "./custom"
export { calculateOnlinePoints } from "./online"
// Re-export algorithm implementations
export { calculatePScore, type PScoreInput, type PScoreResult } from "./p-score"
export { calculateTraditionalPoints } from "./traditional"

/**
 * Input for event score calculation
 */
export interface EventScoreInput {
  userId: string
  /** Normalized score value (already encoded) */
  value: number
  /** Score status */
  status: "scored" | "cap" | "dnf" | "dns" | "withdrawn"
  /**
   * Pre-computed sort key for proper ordering.
   * Encodes status + value + secondaryValue + tiebreak into a single string.
   * If not provided, sorting falls back to value-only comparison.
   */
  sortKey?: string | null
}

/**
 * Result of event score calculation
 */
export interface EventPointsResult {
  userId: string
  /** Points awarded for this event */
  points: number
  /** Rank in the event (1-indexed) */
  rank: number
}

/**
 * Default scoring configuration
 */
export const DEFAULT_SCORING_CONFIG: ScoringConfig = {
  algorithm: "traditional",
  traditional: {
    step: 5,
    firstPlacePoints: 100,
  },
  tiebreaker: {
    primary: "countback",
  },
  statusHandling: {
    dnf: "last_place",
    dns: "zero",
    withdrawn: "exclude",
  },
}

/**
 * Default traditional config
 */
export const DEFAULT_TRADITIONAL_CONFIG: TraditionalConfig = {
  step: 5,
  firstPlacePoints: 100,
}

/**
 * Default P-Score config
 */
export const DEFAULT_PSCORE_CONFIG: PScoreConfig = {
  allowNegatives: true,
  medianField: "top_half",
}

/**
 * Schemes where lower values are better (ascending sort)
 */
const ASCENDING_SCHEMES = new Set<WorkoutScheme>(["time", "time-with-cap"])

/**
 * Sort scores by performance, using sortKey when available for proper
 * secondary value (reps at cap) and tiebreak ordering.
 */
function sortScoresByPerformance(
  scores: EventScoreInput[],
  scheme: WorkoutScheme,
): EventScoreInput[] {
  const isAscending = ASCENDING_SCHEMES.has(scheme)

  return [...scores].sort((a, b) => {
    // If both have sortKey, use it for complete ordering
    if (a.sortKey && b.sortKey) {
      // sortKey is zero-padded string, lexicographic comparison works
      return a.sortKey.localeCompare(b.sortKey)
    }

    // Fallback: status-based sorting for time-with-cap
    if (scheme === "time-with-cap") {
      if (a.status === "cap" && b.status !== "cap") return 1
      if (a.status !== "cap" && b.status === "cap") return -1
    }

    // Fallback: value-only comparison
    return isAscending ? a.value - b.value : b.value - a.value
  })
}

/**
 * Calculate event points using the configured scoring algorithm.
 *
 * This is the main entry point for scoring calculations. It dispatches
 * to the appropriate algorithm based on configuration.
 *
 * @param eventId - Unique identifier for the event (used for caching)
 * @param scores - Array of athlete scores for this event
 * @param scheme - Workout scheme (determines sort direction)
 * @param config - Scoring configuration
 * @returns Map of userId → points for this event
 *
 * @example
 * ```ts
 * const pointsMap = calculateEventPoints(
 *   "event-123",
 *   [
 *     { userId: "a", value: 60000, status: "scored" },
 *     { userId: "b", value: 65000, status: "scored" },
 *   ],
 *   "time",
 *   { algorithm: "traditional", traditional: { step: 5, firstPlacePoints: 100 } }
 * )
 * // → Map { "a" => 100, "b" => 95 }
 * ```
 */
export function calculateEventPoints(
  _eventId: string,
  scores: EventScoreInput[],
  scheme: WorkoutScheme,
  config: ScoringConfig,
): Map<string, EventPointsResult> {
  if (scores.length === 0) {
    return new Map()
  }

  switch (config.algorithm) {
    case "traditional":
      return calculateTraditionalEventPoints(scores, scheme, config)
    case "p_score":
      return calculatePScoreEventPoints(scores, scheme, config)
    case "winner_takes_more":
      return calculateWinnerTakesMoreEventPoints(scores, scheme, config)
    case "online":
      return calculateOnlineEventPoints(scores, scheme, config)
    case "custom":
      return calculateCustomEventPoints(scores, scheme, config)
    default: {
      // TypeScript exhaustiveness check
      const _exhaustive: never = config.algorithm
      throw new Error(`Unknown scoring algorithm: ${_exhaustive}`)
    }
  }
}

/**
 * Calculate points using traditional (placement-based) scoring
 */
function calculateTraditionalEventPoints(
  scores: EventScoreInput[],
  scheme: WorkoutScheme,
  config: ScoringConfig,
): Map<string, EventPointsResult> {
  const traditionalConfig = config.traditional ?? DEFAULT_TRADITIONAL_CONFIG

  // Separate active scores from inactive
  const activeScores = scores.filter(
    (s) => s.status === "scored" || s.status === "cap",
  )
  const inactiveScores = scores.filter(
    (s) => s.status === "dnf" || s.status === "dns" || s.status === "withdrawn",
  )

  // Sort active scores by performance (uses sortKey when available)
  const sortedActive = sortScoresByPerformance(activeScores, scheme)

  // Assign ranks with tie handling
  const ranked = assignRanks(sortedActive)
  const results = new Map<string, EventPointsResult>()

  // Calculate points for active athletes
  for (const { score, rank } of ranked) {
    const points = calculateTraditionalPoints(rank, traditionalConfig)
    results.set(score.userId, {
      userId: score.userId,
      points,
      rank,
    })
  }

  // Handle inactive athletes based on config
  const lastActiveRank = ranked.length > 0 ? ranked[ranked.length - 1].rank : 0
  for (const score of inactiveScores) {
    if (
      score.status !== "dnf" &&
      score.status !== "dns" &&
      score.status !== "withdrawn"
    ) {
      continue
    }
    const handling = getStatusHandling(score.status, config)
    let points: number
    let rank: number

    switch (handling) {
      case "last_place":
      case "worst_performance":
        // Both get ranked after all active athletes
        rank = lastActiveRank + 1
        points = calculateTraditionalPoints(rank, traditionalConfig)
        break
      case "zero":
        rank = lastActiveRank + 1
        points = 0
        break
      case "exclude":
        // Don't add to results
        continue
    }

    results.set(score.userId, {
      userId: score.userId,
      points,
      rank,
    })
  }

  return results
}

/**
 * Calculate points using Winner Takes More scoring
 * Uses a front-loaded points table that rewards top finishers more heavily
 */
function calculateWinnerTakesMoreEventPoints(
  scores: EventScoreInput[],
  scheme: WorkoutScheme,
  config: ScoringConfig,
): Map<string, EventPointsResult> {
  // Separate active scores from inactive
  const activeScores = scores.filter(
    (s) => s.status === "scored" || s.status === "cap",
  )
  const inactiveScores = scores.filter(
    (s) => s.status === "dnf" || s.status === "dns" || s.status === "withdrawn",
  )

  // Sort active scores by performance (uses sortKey when available)
  const sortedActive = sortScoresByPerformance(activeScores, scheme)

  // Assign ranks with tie handling
  const ranked = assignRanks(sortedActive)
  const results = new Map<string, EventPointsResult>()

  // Calculate points for active athletes using winner_takes_more table
  for (const { score, rank } of ranked) {
    const points = calculateCustomPoints(rank, {
      baseTemplate: "winner_takes_more",
      overrides: {},
    })
    results.set(score.userId, {
      userId: score.userId,
      points,
      rank,
    })
  }

  // Handle inactive athletes based on config
  const lastActiveRank = ranked.length > 0 ? ranked[ranked.length - 1].rank : 0
  for (const score of inactiveScores) {
    if (
      score.status !== "dnf" &&
      score.status !== "dns" &&
      score.status !== "withdrawn"
    ) {
      continue
    }
    const handling = getStatusHandling(score.status, config)
    let points: number
    let rank: number

    switch (handling) {
      case "last_place":
      case "worst_performance":
        // Both get ranked after all active athletes
        rank = lastActiveRank + 1
        points = calculateCustomPoints(rank, {
          baseTemplate: "winner_takes_more",
          overrides: {},
        })
        break
      case "zero":
        rank = lastActiveRank + 1
        points = 0
        break
